mapper.select:
SELECT id, user_id, username, login_ip, status, fail_reason, login_time, logout_time
FROM auth.auth_login_log
WHERE tenant_id = #{tenantId}

    AND username LIKE CONCAT('%', #{q.username}, '%')


    AND status = #{q.status}


    AND login_ip LIKE CONCAT('%', #{q.loginIp}, '%')


    AND login_time >= #{q.beginTime}


    AND login_time <= #{q.endTime}

ORDER BY login_time DESC

SELECT id, user_id, username, login_ip, status, fail_reason, login_time, logout_time
FROM auth.auth_login_log
WHERE tenant_id = #{tenantId}

    AND username LIKE CONCAT('%', #{q.username}, '%')


    AND status = #{q.status}


    AND login_ip LIKE CONCAT('%', #{q.loginIp}, '%')


    AND login_time >= #{q.beginTime}


    AND login_time <= #{q.endTime}

ORDER BY login_time DESC
LIMIT 10000
